def add_spaces(s: str, spaces: List[int]) -> str:
    result = []
    j = 0
    for i, c in enumerate(s):
        while j < len(spaces) and i == spaces[j]:
            result.append(' ')
            j += 1
        result.append(c)
    return ''.join(result)

