int countSequences(int[] differences, int lower, int upper) {
    int count = 0, n = differences.length;
    int[] hidden = new int[n + 1];

    hidden[0] = lower;
    while (true) {
        boolean valid = true;
        for (int i = 1; i <= n; i++) {
            hidden[i] = hidden[i - 1] + differences[i - 1];
            if (hidden[i] < lower || hidden[i] > upper) {
                valid = false;
                break;
            }
        }
        if (valid) count++;

        if (hidden[0] == upper) break;
        hidden[0]++;
    }
    return count;
}

