import java.util.HashSet;

public boolean isValidMatrix(int[][] matrix) {
    int n = matrix.length;
    for (int i = 0; i < n; ++i) {
        HashSet<Integer> row = new HashSet<>(), col = new HashSet<>();
        for (int j = 0; j < n; ++j) {
            row.add(matrix[i][j]);
            col.add(matrix[j][i]);
        }
        if (row.size() != n || col.size() != n)
            return false;
    }
    return true;
}

