int splitAndMinimize(int num) {
    int a = num / 1000;
    int b = (num % 1000) / 100;
    int c = (num % 100) / 10;
    int d = num % 10;
    return ((a * 10 + c) * 10 + b) * 10 + d;
}

int splitAndMinimize(int num) {
    int a = num / 1000;
    int b = (num % 1000) / 100
    int c = (num % 100) / 10;
    int d = num % 10;
