import java.util.Arrays;

public int[] rearrangeArray(int[] nums) {
    Arrays.sort(nums);
    int[] result = new int[nums.length];
    int half = nums.length / 2;
    int j = 0;
    for (int i = 0; i < half; i++) {
        result[j] = nums[i];
        result[j + 1] = nums[half + i];
        j += 2;
    }
    return result;
}

