public int maximumGoodPeople(int[][] statements) {
    int n = statements.length;
    int count_good = 0;
    for(int i = 0; i < n; i++) {
        boolean is_good = true;
        for(int j = 0; j < n; j++) {
            if(statements[j][i] == 1 && statements[i][j] == 0) {
                is_good = false;
                break;
            }
        }
        if(is_good) count_good++;
    }
    return count_good;
}

