public int[] threeConsecutiveIntegers(int num) {
    if (num % 3 == 0) {
        return new int[]{num / 3 - 1, num / 3, num / 3 + 1};
    } else if (num % 3 == 1) {
        return new int[]{(num - 2) / 3, (num + 1) / 3, (num + 4) / 3};
    } else {
        return new int[]{};
    }
}

