import java.util.ArrayList;
import java.util.List;

public List<Integer> maxUniqueEvenSum(int finalSum) {
    List<Integer> result = new ArrayList<>();
    int current = 2;
    while (finalSum > 0) {
        if (finalSum >= current) {
            result.add(current);
            finalSum -= current;
            current += 2;
        } else {
            break;
        }
    }
    return result;
}

