public int countGoodTriplets(int[] nums1, int[] nums2) {
    int n = nums1.length;
    int[] pos1 = new int[n];
    int[] pos2 = new int[n];
    for (int i = 0; i < n; i++) {
        pos1[nums1[i]] = i;
        pos2[nums2[i]] = i;
    }
    int count = 0;
    for (int x = 0; x < n; x++) {
        for (int y = x + 1; y < n; y++) {
            for (int z = y + 1; z < n; z++) {
                if (pos1[x] < pos1[y] && pos1[y] < pos1[z] && pos2[x] < pos2[y] && pos2[y] < pos2[z]) {
                    count++;
                }
            }
        }
    }
    return count;
}

