public int[][] visiblePeople(int[][] heights) {
    int m = heights.length, n = heights[0].length;
    int[][] answer = new int[m][n];

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            for (int k = j+1; k < n && heights[i][j] >= heights[i][k]; k++) {
                if (heights[i][j] > heights[i][k]) answer[i][j]++;
            }
            for (int k = i+1; k < m && heights[i][j] >= heights[k][j]; k++) {
                if (heights[i][j] > heights[k][j]) answer[i][j]++;
            }
        }
    }

    return answer;
}

