public int maxNumberOfCopies(String s, String target) {
    int[] sCounts = new int[26];
    int[] targetCounts = new int[26];

    for (char c : s.toCharArray())
        sCounts[c - 'a']++;

    for (char c : target.toCharArray())
        targetCounts[c - 'a']++;

    int maxCopies = Integer.MAX_VALUE;
    for (int i = 0; i < 26; i++) {
        if (targetCounts[i] > 0)
            maxCopies = Math.min(maxCopies, sCounts[i] / targetCounts[i]);
    }
    return maxCopies;
}

