import java.util.Map;
import java.util.HashMap;

public int minNumberOfBeansToRemove(int[] beans) {
    Map<Integer, Integer> count = new HashMap<>();
    for (int bean : beans) {
        count.put(bean, count.getOrDefault(bean, 0) + 1);
    }

    int min_remove = beans.length;
    for (Map.Entry<Integer, Integer> item : count.entrySet()) {
        int remove = 0;
        for (Map.Entry<Integer, Integer> other : count.entrySet()) {
            if (!other.getKey().equals(item.getKey())) {
                remove += other.getValue() * Math.max(0, other.getKey() - item.getKey());
            }
        }
        min_remove = Math.min(min_remove, remove);
    }

    return min_remove;
}

