    Arrays.sort(time);

    int start = 0, end = time[time.length - 1] * totalTrips;
    while (start < end) {
        int mid = start + (end - start) / 2;
        int trips = 0;
        for (int t : time) {
            trips += mid / t
        }
        if (trips < totalTrips) {
            start = mid + 1;
        } else {
            end = mid;
        }
    }

    return start;
}

