import java.util.*;

public int min_race_time(int[][] tires, int changeTime, int numLaps) {
    int n = tires.length;
    int[] times = new int[n];
    for (int i = 0; i < n; i++)
        times[i] = tires[i][0] + (numLaps - 1) * tires[i][1];
    int min_time = Arrays.stream(times).min().getAsInt() + (numLaps - 1) * changeTime;

    for (int i = 0; i < n; i++)
        for (int j = 0; j < n; j++)
            if (i != j)
                min_time = Math.min(min_time, times[i] + times[j] - tires[i][0] + (numLaps - 2) * changeTime);
    return min_time;
}

