public int countPairs(int[] nums, int k) {
    int[] mod_count = new int[k];
    int count = 0;

    for(int num : nums) {
        mod_count[num % k]++;
    }

    count += mod_count[0] * (mod_count[0] - 1) / 2;

    for(int i = 1; i <= k/2; i++) {
        if (i != k - i) {
            count += mod_count[i] * mod_count[k-i];
        } else {
            count += mod_count[i] * (mod_count[i] - 1) / 2;
        }
    }
    return count;
}

