public int minOperations(Integer[] nums) {
    Arrays.sort(nums, Collections.reverseOrder());
    int sum = 0, half_sum = 0, operations = 0;
    for (int num : nums) sum += num;
    for (int num : nums) {
        half_sum += num;
        operations++;
        if (half_sum >= (sum + 1) / 2) break;
    }
    return operations;
}

