public int minVisibleWhiteTiles(String floor, int numCarpets, int carpetLen) {
    int n = floor.length();
    int visibleWhiteCount = 0;
    for (int i = 0; i < n; i++) visibleWhiteCount += (floor.charAt(i) == '1') ? 1 : 0;

    int coveredTiles = 0;
    for (int i = 0; i < n; i++) {
        if (floor.charAt(i) == '1') {
            int start = Math.max(0, i - carpetLen + 1);
            int end = Math.min(n - carpetLen, i);
            int maxCover = 0;
            for (int firstTile = start; firstTile <= end; firstTile++) {
                int cover = 0;
                for (int j = firstTile; j < firstTile + carpetLen; j++) {
                    cover += (floor.charAt(j) == '1') ? 1 : 0;
                }
                maxCover = Math.max(maxCover, cover);
            }

            coveredTiles += maxCover;
            --numCarpets;
            if (numCarpets == 0) break;
        }
    }

    return visibleWhiteCount - coveredTiles;
}

