public int[] bobArrows(int numArrows, int[] aliceArrows) {
    int[] bob = new int[12];
    for (int i = 11; i >= 0 && numArrows > 0; i--) {
        if (aliceArrows[i] == 0) {
            int shot = Math.min(numArrows, i + 1);
            bob[i] = shot;
            numArrows -= shot;
        }
    }
    return bob;
}

