import java.util.ArrayList;

public ArrayList<Integer> longestRepeatSubstring(String s, String queryCharacters, int[] queryIndices) {
    int k = queryCharacters.length();
    ArrayList<Integer> lengths = new ArrayList<>();

    StringBuilder sCopy = new StringBuilder(s);

    for (int i = 0; i < k; i++) {
        sCopy.setCharAt(queryIndices[i], queryCharacters.charAt(i));
        int maxLen = 0, curLen = 1;
        for (int j = 1; j < sCopy.length(); j++) {
            if (sCopy.charAt(j) == sCopy.charAt(j-1)) {
                curLen++;
            } else {
                maxLen = Math.max(maxLen, curLen);
                curLen = 1;
            }
        }
        maxLen = Math.max(maxLen, curLen);
        lengths.add(maxLen);
    }

    return lengths;
}

