import java.util.ArrayList;
import java.util.List;

public int dfs(int node, int parent, int[] xor_values, List<Integer>[] tree) {
    int xor_value = xor_values[node];
    for (int child : tree[node]) {
        if (child != parent) {
            xor_value ^= dfs(child, node, xor_values, tree);
        }
    }
    return xor_value;
}

public int minimumScore(int[] nums, int[][] edges) {
    int n = nums.length;
    List<Integer>[] tree = new ArrayList[n];

    for (int i = 0; i < n; i++) {
        tree[i] = new ArrayList<>();
    }

    for (int[] edge : edges) {
        tree[edge[0]].add(edge[1]);
        tree[edge[1]].add(edge[0]);
    }

    int[] xor_values = new int[n];
    for (int i = 0; i < n; i++) {
        xor_values[i] = dfs(i, -1, nums, tree);
    }

    int ans = Integer.MAX_VALUE;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            int xor1 = xor_values[i];
            int xor2 = xor_values[j] ^ nums[i];
            int xor3 = nums[i] ^ nums[j];
            int max_xor = Math.max(Math.max(xor1, xor2), xor3);
            int min_xor = Math.min(Math.min(xor1, xor2), xor3);
            ans = Math.min(ans, max_xor - min_xor);
        }
    }

    return ans;
}

