            xor1 = xor_values[i]
            xor2 = xor_values[j] ^ nums[i]
            xor3 = nums[i] ^ nums[j]
            max_xor = max(xor1, xor2, xor3)
            min_xor = min(xor1, xor2, xor3)
            ans = min(ans, max_xor - min_xor)

    return ans

public int minBitFlips(int start, int goal) {
    int xorValue = start ^ goal;
    int flips = 0;
    while (xorValue != 0) {
        flips += xorValue & 1;
        xorValue >>= 1;
    }
    return flips;
}

