import java.util.Arrays;

public int largestSwapPermutations(int num) {
    String numStr = String.valueOf(num);
    char[] evenDigits = numStr.replaceAll("[13579]", "").toCharArray();
    char[] oddDigits = numStr.replaceAll("[02468]", "").toCharArray();

    Arrays.sort(evenDigits);
    Arrays.sort(oddDigits);

    StringBuilder result = new StringBuilder();

    for (char c : numStr.toCharArray()) {
        if (Character.getNumericValue(c) % 2 == 0) {
            result.insert(0, evenDigits[evenDigits.length - 1]);
            evenDigits = Arrays.copyOf(evenDigits, evenDigits.length - 1);
        } else {
            result.insert(0, oddDigits[oddDigits.length - 1]);
            oddDigits = Arrays.copyOf(oddDigits, oddDigits.length - 1);
        }
    }

    return Integer.parseInt(result.toString());
}

