public int findSubarrayLength(int[] nums, int threshold) {
    int n = nums.length, left = 0, right = 0, sum = 0, maxLength = -1;

    while (right < n) {
        sum += nums[right];
        while (sum * (right - left + 1) < threshold * (right - left + 1)) {
            sum -= nums[left];
            left++;
        }
        maxLength = Math.max(maxLength, right - left + 1);
        right++;
    }

    return maxLength;
}

