public int numOfArrays(int n, int maxValue) {
    final int mod = 1_000_000_007;
    int[] dp = new int[maxValue + 1];

    for (int i = 1; i <= maxValue; i++) {
        dp[i] = i;
    }

    for (int i = 1; i < n; i++) {
        for (int j = maxValue; j > 0; j--) {
            dp[j] = (dp[j] + dp[j - 1]) % mod;
        }
    }

    return dp[maxValue];
}

