public int minSwaps(int[] nums) {
    int n = nums.length;
    int minPos = 0, maxPos = 0, swaps = 0;

    for (int i = 1; i < n; i++) {
        if (nums[i] <= nums[minPos])
            minPos = i;
        if (nums[i] >= nums[maxPos])
            maxPos = i;
    }

    swaps = minPos + (n - 1 - maxPos);
    if (minPos < maxPos) swaps--;

    return swaps;
}

