public int shortestUnrollableSequence(int[] rolls, int k) {
    int[] count = new int[k + 1];
    for (int roll : rolls) {
        count[roll]++;
    }

    int len = 1;
    while (true) {
        int max_subsequences = 1;
        for (int i = 1; i <= k; i++) {
            max_subsequences *= count[i] + (len == 1 ? 1 : 0);
        }

        if (max_subsequences < len * rolls.length) {
            return len;
        }

        len++;
    }
}

