public char firstLetterToAppearTwice(String s) {
    int[] occurrences = new int[26];
    for (char c : s.toCharArray()) {
        occurrences[c - 'a']++;
        if (occurrences[c - 'a'] == 2) {
            return c;
        }
    }
    return '?';
}

