public int[] minStopCosts(int[] regular, int[] express, int expressCost) {
    int n = regular.length;
    int[] costs = new int[n];
    int regular_sum = 0, express_sum = expressCost;

    for (int i = 0; i < n; ++i) {
        regular_sum += regular[i];
        express_sum += express[i];
        costs[i] = Math.min(regular_sum, express_sum + expressCost);
    }

    return costs;
}

