public int countArithmeticTriplets(int[] nums, int diff) {
    int count = 0;
    HashMap<Integer, Integer> mp = new HashMap<>();
    for (int num : nums) {
        if (mp.containsKey(num - diff))
            count += mp.get(num - diff);
        mp.put(num, mp.getOrDefault(num, 0) + 1);
    }
    return count;
}

