def longest_ideal_string(s: str, k: int) -> int:
    dp = [0] * 26

    for c in s:
        current = 1
        for i in range(26):
            if abs(i - (ord(c) - ord('a'))) <= k:
                current = max(current, dp[i] + 1)
        dp[ord(c) - ord('a')] = max(dp[ord(c) - ord('a')], current)

    return max(dp)

