public String findSmallestNum(String pattern) {
    StringBuilder num = new StringBuilder("123456789");
    for (int i = 0; i < pattern.length(); ++i) {
        if (pattern.charAt(i) == 'D') {
            int j = i;
            while (j < pattern.length() && pattern.charAt(j) == 'D') {
                ++j;
            }
            num = num.reverse().delete(0, pattern.length() - j + 1).reverse();
            num = num.reverse().append(num.substring(0, pattern.length() - i), i, j + 1);
            i = j;
        }
    }
    return num.substring(0, pattern.length() + 1);
}

