public int maxWeight(int[][] edges) {
    int n = edges.length;
    int[][] dp = new int[n][2];

    class Helper {
        void dfs(int node) {
            for (int i = 1; i < n; ++i) {
                if (edges[i][0] == node) {
                    dfs(i);
                    dp[node][0] += Math.max(dp[i][0], dp[i][1]);
                    dp[node][1] += dp[i][0];
                }
            }
            dp[node][1] += edges[node][1];
        }
    }
    Helper helper = new Helper();
    helper.dfs(0);

    return Math.max(dp[0][0], dp[0][1]);
}

