    s = []
    while n > 0:
        s.append(str(n % base))
        n //= base
    return "".join(reversed(s))

def is_strictly_palindromic(n: int) -> bool:
    for b in range(2, n - 1):
        if not is_palindrome(to_base_str(n, b)):
            return False
    return True

