public int maxConsecutiveRobots(int[] chargeTimes, int[] runningCosts, long budget) {
    int n = chargeTimes.length;
    int maxRobots = 0;
    for (int i = 0; i < n; i++) {
        int maxCharge = 0;
        long runningSum = 0;
        for (int j = i; j < n; j++) {
            maxCharge = Math.max(maxCharge, chargeTimes[j]);
            runningSum += runningCosts[j];
            long cost = maxCharge + runningSum * (j - i + 1);
            if (cost <= budget)
                maxRobots = Math.max(maxRobots, j - i + 1);
            else
                break;
        }
    }
    return maxRobots;
}

