public boolean wellSpacedString(String s, int[] distance) {
    Integer[] first = new Integer[26];
    for (int i = 0; i < s.length(); ++i) {
        char c = s.charAt(i);
        if (first[c - 'a'] == null) {
            first[c - 'a'] = i;
        } else {
            if (distance[c - 'a'] != i - first[c - 'a'] - 1) {
                return false;
            }
        }
    }
    return true;
}

