def well_spaced_string(s: str, distance: List[int]) -> bool:
    first = {
    for i, c in enumerate(s):
        if c not in first:
            first[c] = i
        else:
            if distance[ord(c) - ord('a')] != i - first[c] - 1:
                return False
    return True

