public int longestNiceSubarray(int[] nums) {
    int n = nums.length;
    int maxLen = 1;
    for (int i = 0; i < n; i++) {
        int mask = 0;
        for (int j = i; j < n; j++) {
            mask |= nums[j];
            if ((mask & (mask - 1)) == 0) {
                maxLen = Math.max(maxLen, j - i + 1);
            }
        }
    }
    return maxLen;
}

