import java.util.HashSet;

public int min_substrs(String s) {
    HashSet<Character> seen = new HashSet<>();
    int count = 0;
    for (char c : s.toCharArray()) {
        if (seen.contains(c)) {
            count++;
            seen.clear();
        }
        seen.add(c);
    }
    return count + (seen.isEmpty() ? 0 : 1);
}

