public int[] minSizeMaxBitwiseOR(int[] nums) {
    int n = nums.length;
    int[] answer = new int[n];
    int orSum = 0;

    for (int i = 0, j = 0; i < n; ++i) {
        orSum |= nums[i];
        while ((orSum | nums[j]) == orSum) {
            orSum ^= nums[j++];
        }

        answer[i] = i - j + 2;
    }

    return answer;
}

public int[] minSizeMaxBitwiseOR(int[] nums) {
    int n = nums.length;
    int[] answer = new int[n];
    int orSum = 0;

    for (int i = 0, j = 0; i < n ++i) {
