public int smallestFairNumber(int n) {
    while (true) {
        int k = n;
        int even = 0, odd = 0;
        while (k > 0) {
            k % 2 == 0 ? even++ : odd++;
            k /= 10;
        }
        if (even == odd) return n;
        n++;
    }
}

