import java.util.ArrayList;
import java.util.Arrays;
import java.util.Comparator;
import java.util.List;

public List<String> sortNamesByHeight(String[] names, int[] heights) {
    List<Pair> nameHeightPairs = new ArrayList<>();

    for(int i = 0; i < names.length; i++) {
        nameHeightPairs.add(new Pair(heights[i], names[i]));
    }

    nameHeightPairs.sort((a, b) -> b.height - a.height);

    List<String> sortedNames = new ArrayList<>();
    for(Pair pair : nameHeightPairs) {
        sortedNames.add(pair.name);
    }

    return sortedNames;
}

class Pair {
    int height;
    String name;

    public Pair(int height, String name) {
        this.height = height;
        this.name = name;
    }
}

