    for(int i = 1; i < m - 1; ++i) {
        for(int j = 1; j < n - 1; ++j) {
            int sum = grid[i-1][j-1] + grid[i-1][j] + grid[i-1][j+1]
                      + grid[i][j]
                      + grid[i+1][j-1] + grid[i+1][j] + grid[i+1][j+1];
            maxSum = Math.max(maxSum, sum);
        }
    }
    return maxSum;
}

