public int workerWithLongestTask(int n, int[][] logs) {
    int result = 0;
    int max_time = logs[0][1] - 0;

    for (int i = 1; i < logs.length; ++i) {
        int time = logs[i][1] - logs[i-1][1];
        if (time > max_time) {
            max_time = time;
            result = logs[i][0];
        }
    }
    return result;
}

