public int fixedBoundSubarrays(int[] nums, int minK, int maxK) {
    int count = 0, min_index = -1, max_index = -1;
    for (int i = 0; i < nums.length; i++) {
        if(nums[i]==minK) min_index=i;
        else if(nums[i]==maxK) max_index=i;
        count += Math.min(min_index, max_index)+1;
    }
    return count;
}

