    int startMin1 = Integer.parseInt(start1.substring(3, 5));
    int startHour2 = Integer.parseInt(start2.substring(0, 2));
    int startMin2 = Integer.parseInt(start2.substring(3, 5));

    int endHour1 = Integer.parseInt(end1.substring(0, 2));
    int endMin1 = Integer.parseInt(end1.substring(3, 5));
    int endHour2 = Integer.parseInt(end2.substring(0, 2));
    int endMin2 = Integer.parseInt(end2.substring(3, 5));

    int totalMin1Start = startHour1 * 60 + startMin1;
    int totalMin1End = endHour1 * 60 + endMin1;
