public int countGCDSubarrays(int[] nums, int k) {
    int count = 0;

    for (int i = 0; i < nums.length; ++i) {
        int gcdSoFar = 0;
        for (int j = i; j < nums.length; ++j) {
            gcdSoFar = gcd(gcdSoFar, nums[j]);
            if (gcdSoFar == k) ++count;
        }
    }

    return count;
}

