public int min_operations(int[] nums) {
    int n = nums.length;
    int idx0 = -1;

    for(int i = 0; i < n; i++) {
        if(nums[i] == 0) {
            idx0 = i;
            break;
        }
    }

    int cnt1 = 0, cnt2 = 0;

    for(int i = 1; i < n; i++) {
        if(Math.abs(nums[i] - nums[i - 1]) != 1) {
            cnt1 += Math.abs(nums[i] - nums[i - 1]) - 1;
        }
    }

    for(int i = idx0 + 1; i < n; i++) {
        if(nums[i] < nums[i - 1]) {
            cnt2++;
        }
    }

    return Math.min(cnt1, cnt2);
}

