    n = len(costs)
    workers = sorted([(cost, i) for i, cost in enumerate(costs)])

    cost = 0
    for i in range(k):
        if min(workers[i][1], n - workers[i][1] - 1) < candidates:
            cost += workers[i][0]

    return cost

