public int countLCMSubarrays(int[] nums, int k) {
    int count = 0;
    for (int i = 0; i < nums.length; i++) {
        int curr_lcm = nums[i];
        for (int j = i; j < nums.length; j++) {
            curr_lcm = lcm(curr_lcm, nums[j]);
            if (curr_lcm == k) {
                count++;
            }
        }
    }
    return count;
}

private int lcm(int a, int b) {
    int temp = a;
    while ((temp % b) != 0) {
        temp += a;
    }
    return temp;
}

