public int maxPalindromesSubstrings(String s, int k) {
    int n = s.length();
    if (n < k) {
        return 0;
    }
    int count = 0;
    boolean[][] dp = new boolean[n][n];
    for (int i = n - 1; i >= 0; i--) {
        for (int j = i; j < n; j++) {
            if (i == j) {
                dp[i][j] = true;
            } else if (s.charAt(i) == s.charAt(j)) {
                dp[i][j] = i + 1 > j - 1 || dp[i + 1][j - 1];
            } else {
                dp[i][j] = false;
            }
            if (j - i + 1 >= k && dp[i][j]) {
                count++;
                i = j;
                break;
            }
        }
    }
    return count;
}

