int countSubarraysWithMedian(int[] nums, int k) {
    int ans = 0;
    for (int left = 0; left < nums.length; ++left) {
        int count = 0;
        List<Integer> subarray = new ArrayList<>();
        for (int right = left; right < nums.length; ++right) {
            count += (nums[right] == k) ? 1 : 0;
            int index = Collections.binarySearch(subarray, nums[right]);
            index = index >= 0 ? index : ~index;
            subarray.add(index, nums[right]);
            if (subarray.size() % 2 == 1 && subarray.get(subarray.size() / 2) == k) {
                ans += count;
            }
        }
    }
    return ans;
}

