public int minimumPathCost(int[] stones) {
    int n = stones.length;
    int max_cost = stones[n-1];
    for(int i = 1; i < n-1; ++i){
        max_cost = Math.min(max_cost, Math.max(stones[i], stones[n-1]-stones[i]));
    }
    return max_cost;
}

