public int smallestFactorization(int n) {
    if (n <= 3)
        return n;
    int result = 0, factor = 1;
    for (int i = 2; i <= 5; ++i) {
        while (n % i == 0) {
            result += factor * i;
            factor *= 10;
            n /= i;
        }
    }
    return n == 1 ? result : n;
}

