public boolean isValidPath(int[][] grid, int row, int col, int zeros, int ones) {
    if (row < 0 || col < 0 || row >= grid.length || col >= grid[0].length) {
        return false;
    }
    if (grid[row][col] == 1) {
        ones++;
    } else {
        zeros++;
    }
    if (row == grid.length - 1 && col == grid[0].length - 1) {
        return zeros == ones;
    }
    return isValidPath(grid, row + 1, col, zeros, ones) || isValidPath(grid, row, col + 1, zeros, ones);
}

public boolean equalPath(int[][] grid) {
    return isValidPath(grid, 0, 0, 0, 0);
}

