public int shortest_distance(String[] words, String target, int startIndex) {
    int n = words.length;
    int left = 0, right = 0, i = startIndex;
    while (true) {
        if (words[i].equals(target)) {
            return Math.min(left, right);
        }
        left++;
        right++;
        i = (i + 1) % n;
        if (left == n) {
            break;
        }
    }
    return -1;
}

