public int maxMinPower(int[] stations, int r, int k) {
    int n = stations.length;
    int[] totalPower = new int[n];
    for (int i = 0; i < n; i++) {
        for (int j = Math.max(0, i - r); j <= Math.min(n - 1, i + r); j++) {
            totalPower[j] += stations[i];
        }
    }

    int sumk = 0, minPower = Integer.MAX_VALUE;
    for (int i = r; i < n - r; i++) {
        sumk += stations[i];
        minPower = Math.min(minPower, totalPower[i]);
    }

    for (int j = 0, i = n - 2 * r; j < 2 * r; j++, i--) {
        sumk -= stations[i + r + 1];
        minPower -= stations[j];
        minPower += sumk;
        minPower += k;
        minPower = Math.min(minPower, totalPower[j]);
    }

    return minPower;
}

