public int goodSubarrays(int[] nums, int k) {
    Map<Integer, Integer> count = new HashMap<>();
    int result = 0, prefixSum = 0;

    count.put(0, 1);
    for (int num : nums) {
        prefixSum += num - 1;
        result += count.getOrDefault(prefixSum - k, 0);
        count.put(prefixSum, count.getOrDefault(prefixSum, 0) + 1);
    }

    return result;
}

