def minCost(nums: List[int], k: int) -> int:
    n = len(nums)
    count = [0] * 1001
    dp = [0] * (n + 1)

    i = 0
    for j in range(n):
        count[nums[j]] += 1

        if count[nums[j]] == 2:
            dp[j + 1] = dp[i] + k + (j - i + 1)
        elif count[nums[j]] > 2:
            dp[j + 1] = min(dp[j], dp[j - 1] + 1)
        else:
            dp[j + 1] = dp[j] + 1

        while i <= j and count[nums[i]] >= 2:
