public int maximizeScore(int[] weights, int k) {
    int n = weights.length;
    int[] prefixSum = new int[n + 1];
    for (int i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + weights[i];
    }
    int[][] dp = new int[n][k + 1];
    for (int i = 0; i < n; i++) {
        for (int j = 1; j <= k; j++) {
            dp[i][j] = -1000000000;
        }
    }
    for (int i = 0; i < n; i++) {
        dp[i][1] = prefixSum[i + 1];
        if (i > 0) {
            dp[i][i + 1] = prefixSum[i + 1] - prefixSum[1];
        }
        for (int j = 2; j <= Math.min(i + 1, k); j++) {
            for (int q = 1; q <= i - j + 2; q++) {
                dp[i][j] = Math.max(dp[i][j], dp[i - q][j - 1] + weights[i] + weights[i - q]);
            }
        }
    }
    return dp[n - 1][k] - dp[n - 1][1];
}

