        if i > 0:
            dp[i][i + 1] = prefix_sum[i + 1] - prefix_sum[1]
        for j in range(2, min(i + 1, k) + 1):
            for q in range(1, i - j + 3):
                dp[i][j] = max(dp[i][j], dp[i - q][j - 1] + weights[i] + weights[i - q])

    return dp[n - 1][k] - dp[n - 1][1]

