public int maxChosenIntegers(int[] banned, int n, int maxSum) {
    Set<Integer> bannedSet = new HashSet<>();
    for (int b : banned) {
        bannedSet.addb);
    }
    int count = 0, sum = 0;
    for (int i = n; i >= 1 && maxSum - sum >= i; i--) {
        if (!bannedSet.contains(i)) {
