boolean canReach(int[][] grid, int row, int col) {
    if (row < 0 || col < 0 || row >= grid.length || col >= grid[0].length || grid[row][col] == 0) return false;

    if (row == grid.length - 1 && col == grid[0].length - 1) return true;

    grid[row][col] = 0;

    return canReach(grid, row + 1, col) || canReach(grid, row, col + 1);
}

boolean canDisconnect(int[][] grid) {
    int reachableCount = 0;

    for (int row = 1; row < grid.length; row++) {
        for (int col = 1; col < grid[0].length; col++) {
            if (grid[row][col] == 1 && (canReach(grid, row - 1, col) || canReach(grid, row, col - 1))) {
                reachableCount++;
                if (reachableCount > 1) return true;
            }
        }
    }

    return reachableCount <= 1;
}

