def canReach(grid, row, col):
    if row < 0 or col < 0 or row >= len(grid) or col >= len(grid[0]) or grid[row][col] == 0:
        return False

    if row == len(grid) - 1 and col == len(grid[0]) - 1:
        return True

    grid[row][col] = 0

    return canReach(grid, row + 1, col) or canReach(grid, row, col + 1)

def canDisconnect(grid):
    reachableCount = 0

    for row in range(1, len(grid)):
        for col in range(1, len(grid[0])):
            if gridrow][col] == 1 and (canReach(grid, row - 1, col) or canReach(grid, row, col - 1)):
                reachableCount += 1
                if reachableCount > 1:
                    return True

    return reachableCount <= 1

int maxChosenIntegers(int[] banned, int n, long maxSum) {
    Set<Integer> bannedSet = new HashSet<>();
    for (int num : banned) {
        bannedSet.add(num);
    }
    int chosenIntegers = 0;
    long chosenSum = 0;

    for (int i = n; i > 0 && chosenSum < maxSum; i--) {
        if (!bannedSet.contains(i)) {
            if (chosenSum + i <= maxSum) {
                chosenSum += i;
                chosenIntegers++;
            } else {
                break;
            }
        }
    }

    return chosenIntegers;
}

