public int minimumCapability(int[] nums, int k) {
    int n = nums.length, l = 1, r = (int) 1e9;
    while (l < r) {
        int mid = l + (r - l) / 2, i = 0, cnt = 0;
        for (int j = 0; j < n; ++j) {
            if (nums[j] <= mid) {
                ++cnt;
                i = j + 2;
                while (i + 1 < n && (i == j + 1 || nums[i] > mid)) ++i;
            }
        }
        if (cnt < k) l = mid + 1;
        else r = mid;
    }
    return l;
}

