def solve(nums1, nums2, queries):
    res = []
    for q in queries:
        if q[0] == 1:
            for i in range(q[1], q[2] + 1):
                nums1[i] ^= 1
        elif q[0] == 2:
            f i in range(len(nums1)):
                nums2[i] += nums1[i] * q[1]
        elif q[0] == 3:
            res.append(sum(nums2))
    return res

