def countSquareFreeSubsets(nums):
    from collections import Counter
    counter = Counter(nums)
    MOD = 10**9 + 7

    dp = [[0] * 1001 for _ in range(61)]
    dp[0][0] = 1
    idx = 0
    for num, freq in counteritems():
        idx += 1
        for sq in range(61):
            for ns in range(1001 - freq):
                dp[idx][ns + freq] += dp[idx - 1][ns] * ((1 << freq) - 1) % MOD
                dp[idx][ns + freq] %= MOD
                dp[idx][ns] += dp[idx - 1][ns]
                dp[idx][ns] %= MOD

                if (sq // num) % 2 == 1:
                    dp[idx][ns + freq] -= dp[idx - 1][ns] * ((1 << (freq - 1)) - 1) % MOD
                    if dp[idx][ns + freq] < 0:
                        dp[idx][ns + freq] += MOD
    return dp[idx][0]

public String smallestWordForLCP(int[][] lcp) {
    int n = lcp.length;
    char[] word = new char[n];
    Arrays.fill(word, 'a');
    for (int i = 1; i < n; ++i)
        for (int j = 1; j < n; ++j) {
            if (lcp[i][j] > Math.min(lcp[i - 1][j], lcp[i][j - 1])) {
                word[i + lcp[i][j] - 1] = (char) Math.max(word[i + lcp[i][j] - 1], word[i - 1] + 1);
            } else if (lcp[i][j] < Math.min(lcp[i - 1][j], lcp[i][j - 1])) {
                return "";
            }
        }
    return new String(word);
}

