import java.util.Arrays

public int totalWaysToSplitRanges(int[][] ranges) {
    final int MOD = 1000000007;
    Arrays.sort(ranges, (a, b) -> Integer.compare(a[1], b[1]));
    int overlapping = 0, non_overlapping = 1, prev_end = -1;

    for (int[] range : ranges) {
        if (range[0] <= prev_end) {
            overlapping++;
        } else {
            non_overlapping++;
        }
        prev_end = Math.max(prev_end, range[1]);
    }
    long result = 1;
    for (int i = 1; i <= overlapping; ++i) {
        result = (result * 2) % MOD;
    }
    return (int)result;
}

def total_ways_to_split_ranges(ranges):
    MOD = 10**9 + 7
    ranges.sort(key=lambda x: x[1])
    overlapping, non_overlapping, prev_end = 0, 1, -1

    for start, end in ranges:
        if start <= prev_end:
            overlapping += 1
        else:
            non_overlapping += 1
        prev_end = max(prev_end, end)

    result = 1
    for i in range(1, overlapping + 1):
        result = (result * 2) % MOD

    return result

