def possibleRoots(edges, guesses, k):
    n = len(edges) + 1
    in_degree = [0] * n
    guess_parents = set()

    for guess in guesses:
        guess_parents.add(guess[0])

    for edge in edges:
        in_degree[edge[1]] += 1

    possible_roots = 0
    for i in range(n):
        if in_degree[i] == 0:
            if k == 0 or i in guess_parents:
                possible_roots += 1
        elif in_degree[i] == 1 and len(guesses) - k < in_degree[i]:
            possible_roots += 1

    return possible_roots

