def find_valid_split(nums):
    n = len(nums)
    prefix = [0] * n
    suffix = [0] * n

    prefix[0] = nums[0]
    suffix[-1] = nums[-1]

    for i in range(1, n):
        prefix[i] = prefix[i - 1] * nums[i]

    for i in range(n - 2, -1, -1):
        suffix[i = suffix[i + 1] * nums[i]

    for i in range(n - 1):
        if gcd(prefix[i], suffix[i + 1]) == 1:
            return i

    return -1

def gcd(a, b):
    return a if b == 0 else gcd(b, a % b)

public int numberOfWays(int target, int[][] types) {
    int MOD = 1000000007;
    int[] dp = new int[target + 1];
    dp[0] = 1;
    for (int[] type : types) {
        int count = type[0], marks = type[1];
        int[] dptmp = new int[target + 1];
        for (int i = 0; i <= target; ++i) {
            for (int j = 0; j <= count && j * marks + i <= target; ++j) {
                dptmp[i + j * marks] = (dptmp[i + j * marks] + dp[i]) % MOD;
            }
        }
        dp = dptmp;
    }
    return dp[target];
}

