def beautifulSubarrays(nums):
    odd = [0] * 20
    even = [0] * 20
    even[0] = 1

    for num in nums:
        parity = bin(num).count('1') % 2
        for i in range(19, -1, -1):
            mask = 1 << i
            if num & mask:
                if parity:
                    odd[i], even[i] = even[i], odd[i]
                odd[i] += 1
            else:
                if not parity:
                    odd[i], even[i] = even[i], odd[i]
                even[i] += 1
            num -= num & mask

    ans = 0
    for i in range(20):
        ans += even[i] * (even[i] - 1) // 2
    return ans

