public int maxValueSubstring(String s, String chars, int[] vals) {
    Map<Character, Integer> values = new HashMap<>();

    for (int i = 0; i < chars.length(); i++) {
        values.put(chars.charAt(i), vals[i]);
    }

    int max_cost = 0;
    int cost = 0;

    for (char c : s.toCharArray()) {
        int value = values.containsKey(c) ? values.get(c) : (c - 'a' + 1);

        cost = Math.max(0, cost + value);
        max_cost = Math.max(max_cost, cost);
    }

    return max_cost;
}

