import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;

public List<List<Integer>> distinctRowsFrom(int[] nums) {
    List<HashSet<Integer>> rows = new ArrayList<>();

    for(int num : nums) {
        boolean inserted = false;
        for(HashSet<Integer> row : rows) {
            if(!row.contains(num)) {
                row.add(num);
                inserted = true;
                break;
            }
        }

        if(!inserted) {
            HashSet<Integer> newRow = new HashSet<>();
            newRow.add(num);
            rows.add(newRow);
        }
    }

    List<List<Integer>> result = new ArrayList<>();
    for (HashSet<Integer> row : rows) {
        result.add(new ArrayList<Integer>(row));
    }

    return result;
}

