import java.util.HashSet;
import java.util.Set;

public int[] reachPosition(int n, int p, int[] banned, int k) {
    Set<Integer> banned_positions = new HashSet<>();
    for (int pos : banned) {
        banned_positions.add(pos);
    }

    int[] ans = new int[n];

    for (int i = 0; i < n; ++i) {
        if (banned_positions.contains(i) || i == p) {
            ans[i] = -1;
            continue;
        }

        int steps = 0;
        int an = Math.abs(p - i) / k;
        if ((Math.abs(p - i) % k == 0) && ((an & 1) == (((n - 1) & 1) ^ (k & 1)))) {
            steps = an;
        }
        else {
            steps = -1;
        }

        ans[i] = steps;
    }

    ans[p] = 0;
    return ans;
}

